INSERT INTO public.blog (title, slug, excerpt, content, category, image_url, author, read_time_min, published_at)
VALUES
('Comment trouver le lieu idéal pour votre assemblée générale', 'trouver-lieu-ideal-assemblee-generale', 'Guide complet pour choisir un espace adapté aux besoins de votre association lors de vos événements annuels.', E'Guide complet pour choisir un espace adapté aux besoins de votre association lors de vos événements annuels.\n\nOrganiser une assemblée générale est un moment clé dans la vie de toute association. Le choix du lieu peut faire la différence entre un événement réussi et une expérience frustrante pour vos membres.\n\n## Pourquoi c''est important\n\nLe lieu de votre AG influence directement la participation de vos membres. Un espace bien situé, accessible et confortable encouragera davantage de personnes à se déplacer.\n\n## Nos recommandations\n\nCommencez par définir le nombre de participants attendus, puis cherchez un espace offrant au moins 20% de capacité supplémentaire.', 'Conseils', 'https://images.unsplash.com/photo-1505373877841-8d25f7d46678?w=600&h=400&fit=crop', 'Marie Dupont', 5, '2025-12-15'),
('Les 10 erreurs à éviter quand on loue un espace associatif', 'erreurs-location-espace-associatif', 'De la vérification des assurances au contrat de location, découvrez les pièges courants.', E'De la vérification des assurances au contrat de location, découvrez les pièges courants.\n\nLouer un espace pour votre association peut sembler simple, mais de nombreux pièges guettent les organisateurs peu expérimentés.\n\n## Pourquoi c''est important\n\nUne mauvaise préparation peut entraîner des surcoûts, des conflits avec le propriétaire ou même l''annulation de votre événement.\n\n## Nos recommandations\n\nVérifiez toujours l''assurance du lieu, lisez attentivement le contrat de location, et faites un état des lieux.', 'Guide', 'https://images.unsplash.com/photo-1552664730-d307ca884978?w=600&h=400&fit=crop', 'Pierre Martin', 7, '2025-11-28'),
('Rentabilisez vos espaces inutilisés : le guide du propriétaire', 'rentabiliser-espaces-inutilises', 'Transformez vos salles vides en source de revenus tout en aidant les associations locales.', E'Transformez vos salles vides en source de revenus tout en aidant les associations locales.\n\nDe nombreux propriétaires disposent d''espaces sous-utilisés qui pourraient bénéficier aux associations de leur quartier.\n\n## Pourquoi c''est important\n\nLe partage d''espaces crée une dynamique vertueuse : les propriétaires rentabilisent leurs locaux et les associations trouvent des lieux abordables.\n\n## Nos recommandations\n\nCommencez par évaluer vos espaces disponibles, définissez des créneaux de disponibilité clairs, et fixez des tarifs compétitifs.', 'Propriétaires', 'https://images.unsplash.com/photo-1497215842964-222b430dc094?w=600&h=400&fit=crop', 'Sophie Leroux', 6, '2025-11-10'),
('L''impact des espaces partagés sur la vie associative locale', 'impact-espaces-partages-vie-associative', 'Étude de cas : comment le partage d''espaces renforce le tissu associatif dans les quartiers.', E'Étude de cas : comment le partage d''espaces renforce le tissu associatif dans les quartiers.\n\nLe manque d''espaces est l''un des principaux freins au développement des associations locales.\n\n## Pourquoi c''est important\n\nLes associations qui partagent des espaces développent naturellement des synergies et mutualisent leurs ressources.\n\n## Nos recommandations\n\nEncouragez les rencontres entre associations partageant un même lieu et créez un calendrier partagé.', 'Actualités', 'https://images.unsplash.com/photo-1517048676732-d65bc937f952?w=600&h=400&fit=crop', 'Lucas Bernard', 4, '2025-10-22'),
('Organiser un événement caritatif : checklist complète', 'organiser-evenement-caritatif-checklist', 'Tous les éléments à prévoir pour réussir votre prochain événement de collecte de fonds.', E'Tous les éléments à prévoir pour réussir votre prochain événement de collecte de fonds.\n\nOrganiser un événement caritatif demande une préparation minutieuse.\n\n## Pourquoi c''est important\n\nUn événement bien organisé peut multiplier par deux ou trois le montant des dons collectés.\n\n## Nos recommandations\n\nPrévoyez un budget détaillé, constituez une équipe de bénévoles motivés, et communiquez largement sur les réseaux sociaux.', 'Événements', 'https://images.unsplash.com/photo-1511578314322-379afb476865?w=600&h=400&fit=crop', 'Emma Girard', 8, '2025-10-05'),
('Spacio lance son programme de fidélité pour les associations', 'programme-fidelite-associations', 'Découvrez les avantages exclusifs réservés aux associations qui utilisent régulièrement notre plateforme.', E'Découvrez les avantages exclusifs réservés aux associations qui utilisent régulièrement notre plateforme.\n\nSpacio récompense la fidélité de ses utilisateurs avec un programme d''avantages pensé pour les associations.\n\n## Pourquoi c''est important\n\nLes associations ont souvent des budgets limités. Notre programme de fidélité leur permet de bénéficier de réductions.\n\n## Nos recommandations\n\nInscrivez-vous dès maintenant au programme de fidélité depuis votre espace membre.', 'Actualités', 'https://images.unsplash.com/photo-1556761175-5973dc0f32e7?w=600&h=400&fit=crop', 'Équipe Spacio', 3, '2025-09-18');
